"""Backup module - exports gateway configuration to JSON"""

import json
import logging
import os
from datetime import datetime, timedelta
from pathlib import Path

from . import parser

log = logging.getLogger(__name__)

DEFAULT_BACKUP_DIR = "/var/lib/att_gateway/backups"


class BackupManager:
    """Manages gateway configuration backups."""

    def __init__(self, gateway_client, config, backup_dir=None):
        """Initialize backup manager.

        Args:
            gateway_client: Authenticated ATTGateway instance
            config: Config instance
            backup_dir: Backup directory (optional)
        """
        self.gateway = gateway_client
        self.config = config
        self.backup_dir = backup_dir or config.get_backup_directory()

    def create_backup(self, pages_to_backup=None):
        """Create a backup of gateway configuration.

        Args:
            pages_to_backup: List of page paths to backup (None = all discovered)

        Returns:
            Path to backup file
        """
        log.info("Creating gateway configuration backup...")

        # Ensure backup directory exists
        os.makedirs(self.backup_dir, exist_ok=True)

        # If no specific pages provided, get from discovery
        if not pages_to_backup:
            from .discovery import PageDiscovery
            discovery = PageDiscovery(self.gateway)
            discovered = discovery.discover(force=False)
            pages_to_backup = [p['path'] for p in discovered if p.get('has_forms', False)]
            log.info(f"Backing up {len(pages_to_backup)} pages with forms")

        # Build backup data structure
        backup_data = {
            'backup_date': datetime.now().isoformat(),
            'gateway_host': self.gateway.host,
            'firmware_version': self.gateway.firmware_version,
            'firmware_handler': self.gateway.handler.__class__.__name__,
            'page_count': len(pages_to_backup),
            'pages': {}
        }

        # Backup each page
        for page_path in pages_to_backup:
            try:
                log.debug(f"Backing up {page_path}...")
                page_data = self._backup_page(page_path)
                backup_data['pages'][page_path] = page_data
            except Exception as e:
                log.error(f"Failed to backup {page_path}: {e}")
                # Continue with other pages

        # Generate filename
        timestamp = datetime.now().strftime('%Y-%m-%d-%H%M%S')
        filename = f"backup-{timestamp}.json"
        filepath = os.path.join(self.backup_dir, filename)

        # Save backup
        with open(filepath, 'w') as f:
            json.dump(backup_data, f, indent=2)

        log.info(f"✓ Backup saved to {filepath}")
        log.info(f"  Pages backed up: {len(backup_data['pages'])}")
        log.info(f"  Firmware version: {backup_data['firmware_version']}")

        # Clean up old backups
        self._cleanup_old_backups()

        return filepath

    def _backup_page(self, page_path):
        """Backup a single page.

        Args:
            page_path: Path to page

        Returns:
            Dictionary with page backup data
        """
        # Fetch the page
        response = self.gateway.get_page(page_path)
        html = response.text

        # Parse page title
        from bs4 import BeautifulSoup
        soup = BeautifulSoup(html, 'html.parser')
        title_tag = soup.find('title')
        title = title_tag.text.strip() if title_tag else "Unknown"

        # Extract all forms
        forms = parser.extract_all_forms(html)

        page_data = {
            'title': title,
            'backed_up_at': datetime.now().isoformat(),
            'forms': forms,
        }

        return page_data

    def list_backups(self):
        """List all available backups.

        Returns:
            List of backup file information dictionaries
        """
        if not os.path.exists(self.backup_dir):
            return []

        backups = []

        for filename in os.listdir(self.backup_dir):
            if filename.startswith('backup-') and filename.endswith('.json'):
                filepath = os.path.join(self.backup_dir, filename)

                try:
                    # Get file stats
                    stat = os.stat(filepath)
                    mtime = datetime.fromtimestamp(stat.st_mtime)
                    size = stat.st_size

                    # Try to read backup metadata
                    with open(filepath, 'r') as f:
                        data = json.load(f)

                    backup_info = {
                        'filename': filename,
                        'filepath': filepath,
                        'timestamp': filename.replace('backup-', '').replace('.json', ''),
                        'backup_date': data.get('backup_date'),
                        'firmware_version': data.get('firmware_version'),
                        'page_count': data.get('page_count', 0),
                        'size_bytes': size,
                        'modified': mtime.isoformat(),
                    }

                    backups.append(backup_info)

                except Exception as e:
                    log.warning(f"Error reading backup {filename}: {e}")

        # Sort by timestamp (newest first)
        backups.sort(key=lambda x: x['timestamp'], reverse=True)

        return backups

    def get_latest_backup(self):
        """Get the most recent backup.

        Returns:
            Backup info dictionary, or None if no backups
        """
        backups = self.list_backups()
        return backups[0] if backups else None

    def load_backup(self, backup_identifier=None):
        """Load a backup file.

        Args:
            backup_identifier: Filename, timestamp, or None for latest

        Returns:
            Backup data dictionary
        """
        if not backup_identifier:
            # Get latest
            latest = self.get_latest_backup()
            if not latest:
                raise FileNotFoundError("No backups found")
            filepath = latest['filepath']
        else:
            # Check if it's a full path
            if os.path.isabs(backup_identifier) and os.path.exists(backup_identifier):
                filepath = backup_identifier
            else:
                # Try as filename
                if not backup_identifier.endswith('.json'):
                    backup_identifier = f"backup-{backup_identifier}.json"

                filepath = os.path.join(self.backup_dir, backup_identifier)

                if not os.path.exists(filepath):
                    raise FileNotFoundError(f"Backup not found: {backup_identifier}")

        # Load backup
        with open(filepath, 'r') as f:
            backup_data = json.load(f)

        log.info(f"Loaded backup from {filepath}")
        return backup_data

    def _cleanup_old_backups(self):
        """Clean up old backups based on retention policy."""
        retention_count = self.config.get_backup_retention_count()
        retention_days = self.config.get_backup_retention_days()

        backups = self.list_backups()

        if len(backups) <= retention_count:
            # Within count limit
            return

        log.info(f"Cleaning up old backups (retention: {retention_count} count, {retention_days} days)")

        # Remove backups beyond count limit
        to_remove = []
        for backup in backups[retention_count:]:
            to_remove.append(backup)

        # Also remove backups older than retention days
        cutoff_date = datetime.now() - timedelta(days=retention_days)
        for backup in backups:
            backup_date = datetime.fromisoformat(backup['backup_date'])
            if backup_date < cutoff_date and backup not in to_remove:
                to_remove.append(backup)

        # Remove the backups
        for backup in to_remove:
            try:
                os.remove(backup['filepath'])
                log.info(f"  Removed old backup: {backup['filename']}")
            except Exception as e:
                log.warning(f"  Failed to remove {backup['filename']}: {e}")

    def print_backup_list(self):
        """Print a formatted list of backups."""
        backups = self.list_backups()

        if not backups:
            print("No backups found.")
            return

        print("\n" + "=" * 80)
        print("AVAILABLE BACKUPS")
        print("=" * 80)
        print(f"{'Timestamp':<20} {'Firmware':<12} {'Pages':<8} {'Size':<10} {'Date'}")
        print("-" * 80)

        for backup in backups:
            size_kb = backup['size_bytes'] / 1024
            size_str = f"{size_kb:.1f} KB"
            date_str = backup['backup_date'][:19]  # Trim to seconds

            print(f"{backup['timestamp']:<20} "
                  f"{backup['firmware_version']:<12} "
                  f"{backup['page_count']:<8} "
                  f"{size_str:<10} "
                  f"{date_str}")

        print("=" * 80)
        print(f"Total: {len(backups)} backup(s)")
        print(f"Backup directory: {self.backup_dir}")
        print()
